const { initializeApp, cert } = require('firebase-admin/app');
const { getDatabase } = require('firebase-admin/database');
const usb = require('usb');
const serviceAccount = require('./serviceAccount.json');

initializeApp({
  credential: cert(serviceAccount),
  databaseURL: 'https://dulce-patata-e96c2-default-rtdb.europe-west1.firebasedatabase.app'
});

const db = getDatabase();
console.log('Dulce Patata - Escuchando pedidos...');

// ── CONFIGURACIÓN DEL TICKET / IMPRESORA (se lee y actualiza en vivo desde el panel web) ──
let ticketConfig = {
  nombre: 'DULCE PATATA FOOD',
  direccion: 'Carretera de Malaga 111, Granada',
  telefono: '604 82 31 80',
  despedida: 'Gracias por tu pedido!',
  textoPago: 'Pagar en caja',
  anchoPapel: 80,
  copias: 1,
  autoImprimir: true
};
db.ref('config/ticketConfig').on('value', (snap) => {
  if (snap.exists()) {
    ticketConfig = Object.assign({}, ticketConfig, snap.val());
    console.log('Configuracion del ticket actualizada:', JSON.stringify(ticketConfig));
  }
});

