function encodeStr(str) {
  const map = {'á':'a','é':'e','í':'i','ó':'o','ú':'u','Á':'A','É':'E','Í':'I','Ó':'O','Ú':'U','ñ':'n','Ñ':'N','ü':'u','Ü':'U','¡':'!','¿':'?'};
  return (str||'').split('').map(c => map[c]||c).join('');
}

function getDevice() {
  const devices = usb.getDeviceList();
  const device = devices.find(d => d.deviceDescriptor.idVendor === 0x0416 && d.deviceDescriptor.idProduct === 0x5011);
  if (!device) return null;
  device.open();
  const iface = device.interfaces[0];
  iface.claim();
  return { device, ep: iface.endpoints.find(e => e.direction === 'out') };
}

function imprimirUnaCopia(ticket, cb) {
  const conn = getDevice();
  if (!conn) { console.error('Impresora no encontrada'); cb(); return; }

  const ESC = 0x1B, GS = 0x1D;
  const d = [];
  const push = s => { for(const c of encodeStr(s)) d.push(c.charCodeAt(0)); };
  const center = () => d.push(ESC, 0x61, 0x01);
  const left = () => d.push(ESC, 0x61, 0x00);
  const big = () => d.push(ESC, 0x21, 0x30);
  const normal = () => d.push(ESC, 0x21, 0x00);
  const bold = on => d.push(ESC, 0x45, on ? 0x01 : 0x00);

  // Inicializar
  d.push(ESC, 0x40);

  // Logo centrado
  center();
  const bpr = (LOGO_W + 7) >> 3;
  d.push(GS, 0x76, 0x30, 0x00, bpr & 0xFF, (bpr >> 8) & 0xFF, LOGO_H & 0xFF, (LOGO_H >> 8) & 0xFF);
  LOGO_DATA.forEach(b => d.push(b));

  // Nombre del negocio
  center();
  big();
  push(ticketConfig.nombre + '\n');
  normal();
  push(ticketConfig.direccion + '\n');
  push(ticketConfig.telefono + '\n');
  push('------------------------------------------------\n');

  // HORA RECOGIDA centrada
  if (ticket.slotTime) {
    center();
    push('HORA RECOGIDA\n');
    big();
    push(ticket.slotTime + '\n');
    normal();
  }

  // Nombre cliente grande centrado
  center();
  big();
  push((ticket.name || '').toUpperCase() + '\n');
  normal();
  if (ticket.phone) push('Tlfno. ' + ticket.phone + '\n');
  push('------------------------------------------------\n');

  // PEDIDO centrado grande
  center();
  big();
  push('PEDIDO ' + ticket.orderNum + '\n');
  normal();
  push(ticket.time + '\n');
  push('------------------------------------------------\n');

  // Productos
  left();
  (ticket.items || []).forEach(item => {
    const partes = encodeStr(item.name || '').split(' + ');
    const nombrePrincipal = partes[0];
    const extrasNombre = partes.slice(1);
    const extrasArr = item.extras || [];
    const precio = (item.subtotal || 0).toFixed(2) + ' EUR';
    const W = ticketConfig.anchoPapel === 58 ? 32 : 48;
    const prefix = item.qty + 'x ';
    const spaces = W - prefix.length - nombrePrincipal.length - precio.length;
    if (spaces >= 0) {
      push(prefix + nombrePrincipal + ' '.repeat(spaces) + precio + '\n');
    } else {
      push(prefix + nombrePrincipal.substring(0, W - prefix.length) + '\n');
      push(' '.repeat(W - precio.length) + precio + '\n');
    }
    // Extras del nombre (queso, gratinado) - precio entre paréntesis
    extrasNombre.forEach(extra => {
      const conParentesis = extra
        .replace(/\s*\+\s*([\d]+[,\.]?[\d]*)\s*€/, ' (+$1 EUR)')
        .trim();
      push('     - ' + encodeStr(conParentesis) + '\n');
    });
    // Extras del array (ingredientes)
    if (Array.isArray(extrasArr)) {
      extrasArr.forEach(extra => {
        const conParentesis = extra
          .replace(/\s*\+\s*([\d]+[,\.]?[\d]*)\s*€/, ' (+$1 EUR)')
          .trim();
        push('     - ' + encodeStr(conParentesis) + '\n');
      });
    }
  });

  push('------------------------------------------------\n');

  // TOTAL
  center();
  const totalStr = 'TOTAL';
  const totalPrecio = (ticket.total || 0).toFixed(2) + ' EUR';
  big();
  push(totalPrecio + '\n');
  normal();
  push(ticketConfig.textoPago + '\n');

  if (ticket.notes) {
    left();
    push('------------------------------------------------\n');
    bold(true); push('NOTAS: '); bold(false);
    push(ticket.notes + '\n');
  }

  center();
  push('------------------------------------------------\n');
  push(ticketConfig.despedida + '\n');
  push('\n\n\n');

  d.push(GS, 0x56, 0x42, 0x00);

  conn.ep.transfer(Buffer.from(d), (err) => {
    conn.device.close();
    if (err) console.error('Error:', err.message);
    else console.log('Impreso #' + ticket.orderNum);
    cb(!err);
  });
}

// Imprime el ticket tantas veces como copias se hayan configurado (1 por defecto).
// cbFinal recibe true solo si TODAS las copias salieron bien.
function imprimir(ticket, cbFinal) {
  const copias = Math.max(1, parseInt(ticketConfig.copias, 10) || 1);
  let hechas = 0;
  let todoBien = true;
  function siguiente() {
    if (hechas >= copias) { cbFinal(todoBien); return; }
    hechas++;
    imprimirUnaCopia(ticket, (ok) => {
      if (!ok) todoBien = false;
      setTimeout(siguiente, 300);
    });
  }
  siguiente();
}

const printQueue = [];
let printing = false;

// Marca el pedido como "en preparación" en Firebase (lo que ve la pantalla de cocina/panel en vivo).
// Usa la misma ruta y normalización que la web: orderStatus/{fecha}/{numero sin # ni T}
function marcarEnPreparacion(orderNum, fecha) {
  const key = String(orderNum).replace(/#/g, '').replace(/^T/, '');
  db.ref('orderStatus/' + fecha + '/' + key).set('preparando')
    .then(() => console.log('Pedido #' + orderNum + ' marcado como en preparacion'))
    .catch((e) => console.warn('No se pudo marcar como en preparacion:', e.message));
}

function procesarCola() {
  if (printing || printQueue.length === 0) return;
  printing = true;
  const { ticket, snap } = printQueue.shift();
  imprimir(ticket, (todoBien) => {
    snap.ref.update({ _impreso: true, _reimprimir: false });
    // Solo avanzamos el estado en pedidos NUEVOS (no en reimpresiones manuales)
    // y solo si de verdad se imprimio bien. Si fallo, se deja tal cual para que
    // alguien lo vea e imprima a mano.
    if (todoBien && !ticket._reimprimir) {
      marcarEnPreparacion(ticket.orderNum, today);
    }
    printing = false;
    setTimeout(procesarCola, 500);
  });
}

const today = new Date().toISOString().slice(0, 10);
db.ref('tickets/' + today).on('child_added', (snap) => {
  const t = snap.val();
  if (!t || t._impreso) return;
  // Si el auto-imprimir está apagado, solo imprimimos las reimpresiones manuales
  // (las que se mandan desde el botón "Imprimir" del panel). Los pedidos nuevos
  // se marcan como vistos sin imprimir, y se pueden imprimir a mano cuando quieras.
  if (!ticketConfig.autoImprimir && !t._reimprimir) {
    console.log('Auto-imprimir desactivado, no se imprime #' + t.orderNum + ' (usa el boton manual)');
    snap.ref.update({ _impreso: true });
    return;
  }
  console.log((t._reimprimir ? 'Reimprimir' : 'Nuevo') + ': #' + t.orderNum);
  printQueue.push({ ticket: t, snap });
  procesarCola();
});
